import json
from get_job_listings import find_jobs, extract_job_links, convert_experience_to_filter

output_items = []

for item in _items:
    try:
        current_item = item.get('json', {})
        search_terms = []

        raw_titles = current_item.get("job_titles")
        experience_filter = convert_experience_to_filter(current_item.get("total_experience"))
        work_format_filter = current_item.get("work_formats")

        if raw_titles:
            if isinstance(raw_titles, list):
                search_terms.extend(raw_titles)
            elif isinstance(raw_titles, str):
                try:
                    cleaned_titles = json.loads(raw_titles)
                    if isinstance(cleaned_titles, list):
                        search_terms.extend(cleaned_titles)
                    else:
                        search_terms.append(cleaned_titles)
                except Exception:
                    cleaned = raw_titles.replace("[", "").replace("]", "").replace('"', '')
                    search_terms.extend([t.strip() for t in cleaned.split(",") if t.strip()])

        unique_vacancies = set()

        for term in search_terms:
            if not term:
                continue

            try:
                target_search_url = find_jobs(
                    text=term,
                    search_fields=["name", "description"],
                    experience=experience_filter,
                    work_formats=work_format_filter,
                    employment_forms=["FULL"]
                )
                links = extract_job_links(target_search_url)
                if links:
                    unique_vacancies.update(links)
            except Exception:
                pass



        if unique_vacancies:
            for link in unique_vacancies:
                output_items.append({
                    "json": {
                        "job_link": link,
                        "searched_terms": search_terms,
                        "experience_filter": experience_filter,
                        "work_format_filter": work_format_filter
                    }
                })
        else:
            output_items.append({
                "json": {
                    "job_link": None,
                    "status": "No jobs found",
                    "searched_terms": search_terms
                }
            })

    except Exception as e:
        output_items.append({
            "json": {
                "error": f"Job search failed: {str(e)}",
                "job_link": None
            }
        })

return output_items

