import re

output_items = []

for item in _items:
    sql_job_titles = "[]"
    sql_keywords = "[]"

    try:
        current_json = item.get("json", {})
        raw_llm_text = current_json.get("text") or current_json.get("output") or ""
        if raw_llm_text:
            cleaned_text = re.sub(r"```json\s*|\s*```", "", raw_llm_text).strip()
            start_idx = cleaned_text.find("{")
            end_idx = cleaned_text.rfind("}")

            if start_idx != -1 and end_idx != -1:
                cleaned_text = cleaned_text[start_idx:end_idx+1]
                cleaned_text = re.sub(r',\s*([\]}])', r'\1', cleaned_text)

                parsed_payload = json.loads(cleaned_text)
                job_titles = parsed_payload.get("job_titles", [])
                keywords = parsed_payload.get("keywords", [])

                if isinstance(job_titles, list):
                    sql_job_titles = json.dumps(job_titles, ensure_ascii=False)
                if isinstance(keywords, list):
                    sql_keywords = json.dumps(keywords, ensure_ascii=False)

    except Exception as e:
        pass

    output_items.append({
        "json": {
            "job_titles": sql_job_titles,
            "keywords": sql_keywords
        }
    })

return output_items

